var leadersObject = {
    op: "LoadItems",
    listUrl: $util.LangUrl + "/AboutUs/Lists/leaders",
    viewName: "Home",
  };

LoadData(leadersObject, BindLeaders);
  

function BindLeaders(data, listName) {
var html_content = "";
if (data != undefined && data.length > 0) {
  $.each(data, function (key, item) {
    html_content +=
    `<div class="col-md-4"><div class="leader_member"> <div class="leader-img">${item.PublishingRollupImage? item.PublishingRollupImage: '<img src="/Style Library/GSTC/images/icon_head.svg" style="height:80px;" />' }</div> ${item.Title} <div class="text-black-50 mt-1"> ${item.position}</div></div></div>`;
  });
  $("#Leaders_data").html(html_content);
 
} else {
  $("#Leaders_data").html($util.getLocalString("NoDataForSearch"));
}
}



$(document).ready(function () {

            //var startTime = '00:00 AM';
           // var endTime = '6:00 AM';
			var startTime = '2:00 AM';
            var endTime = '10:00 AM';
			var startTime2 = '4:00 PM';
           var endTime2 = '8:00 PM';

            var curr_time = getRiyadhTime();
            
            if (get24Hr(curr_time) > get24Hr(startTime) && get24Hr(curr_time) < get24Hr(endTime)) {

                //in between these two times
                //alert("Yes");
                $("div.chat").hide();
            } else {
              // $("div.chat").show();

            }
			
			//Ramdan
			if (get24Hr(curr_time) > get24Hr(startTime2) && get24Hr(curr_time) < get24Hr(endTime2)) {

                //in between these two times
                //alert("Yes");
                $("div.chat").hide();
            }
			else {
              // $("div.chat").show();

            }

			
			
			
			

            function get24Hr(time) {
                var hours = Number(time.match(/^(\d+)/)[1]);
                var AMPM = time.match(/\s(.*)$/)[1];
                if (AMPM == "PM" && hours < 12) hours = hours + 12;
                if (AMPM == "AM" && hours == 12) hours = hours - 12;

                var minutes = Number(time.match(/:(\d+)/)[1]);
                hours = hours * 100 + minutes;
                console.log(time + " - " + hours);
				
				
                return hours;
            }

            function getRiyadhTime() {
                //var currentTime = new Date()
                var d = new Date();
                var local = d.getTime();
                var offset = d.getTimezoneOffset() * (60 * 1000);
                var utc = new Date(local + offset);
                var riyadh = new Date(utc.getTime() + (3 * 60 * 60 * 1000));


                var hours = riyadh.getHours();
                var minutes = riyadh.getMinutes();

                if (minutes < 10) minutes = "0" + minutes;

                var suffix = "AM";
                if (hours >= 12) {
                    suffix = "PM";
                    hours = hours - 12;
                }
                if (hours == 0) {
                    hours = 12;
                }
              
				var current_time = hours + ":" + minutes +  " " + suffix;
                return current_time;

            }






        });
